import type { Hono, MiddlewareHandler } from "hono";
import { detectVaguePassages } from "../elicitation-detect.js";
import {
  generateQuestions,
  generateFollowUp,
} from "../elicitation-questions.js";
import { generateIntakeQuestion } from "../intake-question.js";
import { rewriteElicitation } from "../elicitation-rewrite.js";
import type { ActiveLayer } from "../shared/layer-stack-hash.js";

export function registerElicitationRoutes(
  app: Hono,
  authMiddleware: () => MiddlewareHandler,
) {
  app.use("/elicitation", authMiddleware());
  app.use("/elicitation/*", authMiddleware());

  app.post("/elicitation/detect", async (c) => {
    const body = await c.req.json<{
      text: string;
      specificityScore?: number;
    }>();

    if (!body.text) {
      return c.json({ error: "text is required" }, 400);
    }

    const result = await detectVaguePassages(body.text, body.specificityScore);
    return c.json({ elicitation: result });
  });

  app.post("/elicitation/questions", async (c) => {
    const body = await c.req.json<{
      quotedText: string;
      vaguenessType: string;
      paragraphBefore: string;
      paragraphAfter: string;
      documentRegister?: string;
      // Follow-up fields (optional — if present, generates follow-up instead)
      originalQuestion?: string;
      userResponse?: string;
    }>();

    if (!body.quotedText || !body.vaguenessType) {
      return c.json(
        { error: "quotedText and vaguenessType are required" },
        400,
      );
    }

    // Truncate all text fields to prevent unbounded token spend
    const quotedText = body.quotedText.slice(0, 1000);
    const paragraphBefore = (body.paragraphBefore ?? "").slice(0, 500);
    const paragraphAfter = (body.paragraphAfter ?? "").slice(0, 500);

    // Follow-up mode
    if (body.originalQuestion && body.userResponse) {
      const followUp = await generateFollowUp({
        quotedText,
        vaguenessType: body.vaguenessType as Parameters<
          typeof generateFollowUp
        >[0]["vaguenessType"],
        originalQuestion: body.originalQuestion,
        userResponse: body.userResponse,
      });
      return c.json({ followUp });
    }

    // Question generation mode
    const questions = await generateQuestions({
      quotedText,
      vaguenessType: body.vaguenessType as Parameters<
        typeof generateQuestions
      >[0]["vaguenessType"],
      paragraphBefore,
      paragraphAfter,
      documentRegister: body.documentRegister,
    });
    return c.json({ questions });
  });

  // ─── Elicitation Rewrite ─────────────────────────────────────────────

  app.post("/elicitation/rewrite", async (c) => {
    const body = await c.req.json<{
      sessionId?: string;
      chunkId?: string;
      quotedText: string;
      vaguenessType?: string;
      intakeQuestion?: string;
      intakeAnswer?: string;
      activeLayers?: ActiveLayer[];
    }>();

    if (!body.quotedText) {
      return c.json({ error: "quotedText is required" }, 400);
    }

    if (body.intakeAnswer && !body.intakeQuestion) {
      return c.json(
        { error: "intakeQuestion is required when intakeAnswer is provided" },
        400,
      );
    }

    if (body.intakeAnswer && body.intakeAnswer.length > 2000) {
      return c.json(
        { error: "intakeAnswer exceeds 2000 character limit" },
        400,
      );
    }

    const quotedText = body.quotedText.slice(0, 1000);
    const vaguenessType = body.vaguenessType ?? "unknown";
    const intakeQuestion =
      body.intakeQuestion ??
      (body.intakeAnswer
        ? undefined
        : await generateIntakeQuestion({
            quotedText,
            vaguenessType: vaguenessType as Parameters<
              typeof generateIntakeQuestion
            >[0]["vaguenessType"],
          }));

    if (!intakeQuestion) {
      return c.json({ error: "intakeQuestion is required" }, 400);
    }

    const result = await rewriteElicitation({
      sessionId: body.sessionId,
      chunkId: body.chunkId,
      passage: {
        quotedText,
        vaguenessType,
      },
      intakeQuestion,
      intakeAnswer: body.intakeAnswer,
      activeLayers: body.activeLayers,
    });

    return c.json(result);
  });
}

