import { NextResponse } from "next/server";
import { auth } from "@clerk/nextjs/server";
import { and, eq } from "drizzle-orm";
import { db } from "@/db";
import {
  elicitationDpoPairs,
  elicitationPredictions,
} from "@/db/schema";

type AcceptBody = {
  sessionId?: string;
  chunkId?: string;
  documentId?: string;
  chosenOptionId?: string;
  intakeQuestion?: string;
  intakeAnswer?: string;
};

export async function POST(req: Request) {
  const { userId } = await auth();
  if (!userId) {
    return NextResponse.json({ error: "unauthorized" }, { status: 401 });
  }

  const body = (await req.json()) as AcceptBody;
  const {
    sessionId,
    chunkId,
    documentId,
    chosenOptionId,
    intakeQuestion,
    intakeAnswer,
  } = body;

  if (
    !sessionId ||
    !chunkId ||
    !documentId ||
    !chosenOptionId ||
    !intakeQuestion ||
    !intakeAnswer
  ) {
    return NextResponse.json({ error: "invalid_request" }, { status: 400 });
  }

  const [prediction] = await db
    .select()
    .from(elicitationPredictions)
    .where(
      and(
        eq(elicitationPredictions.sessionId, sessionId),
        eq(elicitationPredictions.chunkId, chunkId),
      ),
    )
    .limit(1);

  if (!prediction) {
    return NextResponse.json({ error: "no_prediction_log" }, { status: 400 });
  }

  if (!prediction.optionIds.includes(chosenOptionId)) {
    return NextResponse.json(
      { error: "invalid_chosen_option" },
      { status: 400 },
    );
  }

  const rejectedOptionIds = prediction.optionIds.filter(
    (optionId) => optionId !== chosenOptionId,
  );

  try {
    await db.insert(elicitationDpoPairs).values({
      sessionId,
      chunkId,
      documentId,
      userId,
      chosenOptionId,
      rejectedOptionIds,
      internalPredictionId: prediction.internalPredictionId,
      layerStackHash: prediction.layerStackHash,
      intakeQuestion,
      intakeAnswer,
    });
    return NextResponse.json({ ok: true });
  } catch (error) {
    if (isCheckConstraintError(error)) {
      return NextResponse.json({ error: "invalid_triplet" }, { status: 400 });
    }
    throw error;
  }
}

function isCheckConstraintError(error: unknown): boolean {
  return /check constraint|jsonb_array_length|violates check constraint/i.test(
    collectErrorText(error),
  );
}

function collectErrorText(error: unknown): string {
  if (error instanceof Error) {
    const causeText =
      "cause" in error ? collectErrorText((error as Error & { cause?: unknown }).cause) : "";
    return `${error.message} ${causeText}`.trim();
  }

  if (error && typeof error === "object" && "message" in error) {
    return String((error as { message?: unknown }).message ?? "");
  }

  return "";
}

