// apps/web/src/lib/training-rows/fatigue.ts
import type { SurfaceOrigin, TrainingAction } from "@texturaize/pipeline-worker/shared";

interface FatigueInput {
  action: TrainingAction;
  dwellMs: number;
  failureModeSeverity: number;
  surfaceOrigin: SurfaceOrigin;
  queuePosition: number;
}

export function detectFatigueAccept(input: FatigueInput): boolean {
  if (input.action !== "accept") return false;
  if (input.dwellMs >= 2000) return false;
  if (input.failureModeSeverity <= 0.3) return false;
  if (input.surfaceOrigin !== "scout-web") return false;
  if (input.queuePosition <= 7) return false;
  return true;
}
```

