// apps/web/src/lib/training-rows/user-tier.ts
import { clerkClient } from "@clerk/nextjs/server";
import type { UserTier } from "@pipeline-shared/training-row-types";

const VALID_TIERS = new Set<UserTier>([
  "expert-calibrator",
  "expert",
  "standard",
  "unknown",
]);

export async function resolveUserTier(userId: string): Promise<UserTier> {
  try {
    const client = await clerkClient();
    const user = await client.users.getUser(userId);
    const raw = user.publicMetadata?.tier;
    if (typeof raw === "string" && VALID_TIERS.has(raw as UserTier)) {
      return raw as UserTier;
    }
    return "unknown";
  } catch {
    return "unknown";
  }
}
```

