import { NextResponse } from "next/server";
import { auth } from "@clerk/nextjs/server";
import { and, eq } from "drizzle-orm";
import { db } from "@/db";
import {
  elicitationPredictions,
  elicitationRejections,
} from "@/db/schema";

type RejectBody = {
  sessionId?: string;
  chunkId?: string;
  documentId?: string;
  freeTextResponse?: string;
  intakeQuestion?: string;
  intakeAnswer?: string;
};

export async function POST(req: Request) {
  const { userId } = await auth();
  if (!userId) {
    return NextResponse.json({ error: "unauthorized" }, { status: 401 });
  }

  const body = (await req.json()) as RejectBody;
  const {
    sessionId,
    chunkId,
    documentId,
    freeTextResponse,
    intakeQuestion,
    intakeAnswer,
  } = body;

  if (
    !sessionId ||
    !chunkId ||
    !documentId ||
    !freeTextResponse?.trim() ||
    !intakeQuestion ||
    !intakeAnswer
  ) {
    return NextResponse.json({ error: "invalid_request" }, { status: 400 });
  }

  const [prediction] = await db
    .select()
    .from(elicitationPredictions)
    .where(
      and(
        eq(elicitationPredictions.sessionId, sessionId),
        eq(elicitationPredictions.chunkId, chunkId),
      ),
    )
    .limit(1);

  if (!prediction) {
    return NextResponse.json({ error: "no_prediction_log" }, { status: 400 });
  }

  await db.insert(elicitationRejections).values({
    sessionId,
    chunkId,
    documentId,
    userId,
    freeTextResponse: freeTextResponse.trim(),
    optionsShown: prediction.optionIds,
    layerStackHash: prediction.layerStackHash,
    intakeQuestion,
    intakeAnswer,
  });

  return NextResponse.json({ ok: true });
}

