// apps/web/src/lib/training-rows/emit.ts
import { db } from "@/db";
import { trainingRows } from "@/db/schema";
import { detectFatigueAccept } from "./fatigue";
import { resolveUserTier } from "./user-tier";
import type {
  TrainingAction,
  DisplayMode,
  SurfaceOrigin,
  SignalType,
  EngagementType,
} from "@pipeline-shared/training-row-types";

interface EmitParams {
  userId: string;
  sessionId: string;
  pieceId: string;
  paragraphIdx: number;
  attemptId: string;
  action: TrainingAction;
  alternativesShown: string[];
  alternativePicked: string | null;
  dwellMs: number;
  queuePosition: number;
  surfaceOrigin: SurfaceOrigin;
  attemptModelConfidence: number;
  rulesShown: string[];
  displayMode: DisplayMode;
  internalPrediction: string;
  failureModeSeverity: number;
}

function actionToSignalType(action: TrainingAction): SignalType {
  switch (action) {
    case "accept":
      return "agreement";
    case "reject":
    case "withhold":
      return "rejection";
    case "pick":
    case "free_text":
      return "correction";
  }
}

export async function emitTrainingRow(params: EmitParams): Promise<void> {
  const userTier = await resolveUserTier(params.userId);

  const fatigue = detectFatigueAccept({
    action: params.action,
    dwellMs: params.dwellMs,
    failureModeSeverity: params.failureModeSeverity,
    surfaceOrigin: params.surfaceOrigin,
    queuePosition: params.queuePosition,
  });

  const engagementType: EngagementType = fatigue ? "fatigue_accept" : "engaged";

  // Weight: only experts (and calibrators) count at 1.0; standard = 0.0 until
  // verified-editorial earned. Fatigue-accept demotes to 0 regardless of tier.
  const isExpert = userTier === "expert" || userTier === "expert-calibrator";
  const trainingWeight = fatigue ? 0 : isExpert ? 1.0 : 0;

  await db.insert(trainingRows).values({
    userId: params.userId,
    sessionId: params.sessionId,
    pieceId: params.pieceId,
    paragraphIdx: params.paragraphIdx,
    attemptId: params.attemptId,
    action: params.action,
    alternativesShown: params.alternativesShown,
    alternativePicked: params.alternativePicked,
    dwellMs: params.dwellMs,
    queuePosition: params.queuePosition,
    userTier,
    surfaceOrigin: params.surfaceOrigin,
    signalType: actionToSignalType(params.action),
    trainingWeight,
    engagementType,
    attemptModelConfidence: params.attemptModelConfidence,
    rulesShown: params.rulesShown,
    displayMode: params.displayMode,
    internalPrediction: params.internalPrediction,
  });
}
