**Step 3: Write the emit helper**
```typescript
// apps/web/src/lib/training-rows/emit.ts
import { db } from "@/db";
import { trainingRows } from "@/db/schema";
import { detectFatigueAccept } from "./fatigue";
import { resolveUserTier } from "./user-tier";
import type {
  TrainingAction,
  DisplayMode,
  SurfaceOrigin,
  SignalType,
  EngagementType,
} from "@pipeline-shared/training-row-types";

interface EmitParams {
  userId: string;
  sessionId: string;
  pieceId: string;
  paragraphIdx: number;
  attemptId: string;
  action: TrainingAction;
  alternativesShown: string[];
  alternativePicked: string | null;
  dwellMs: number;
  queuePosition: number;
  surfaceOrigin: SurfaceOrigin;
  attemptModelConfidence: number;
  rulesShown: string[];
  displayMode: DisplayMode;
  /** Null allowed for pre-epoch / capture miss; emit logs a warning but still writes. */
  internalPrediction: string | null;
  failureModeSeverity: number;
}

/**
 * Signal-type mapping. See plan § "Action → signal-type mapping (load-bearing)".
 * Reference: docs/research/q1-training-loop/q1-spec.md — channels MUST NOT blend.
 */
function computeSignalType(params: EmitParams): SignalType {
  switch (params.action) {
    case "accept":
      return "agreement";
    case "reject":
    case "withhold":
      return "rejection";
    case "free_text":
      return "correction";
    case "pick":
      // Pick that matches the model's private prediction = agreement.
      // Pick that diverges = correction. This is the load-bearing distinction
      // for the DPO-vs-BT-RM channel split in q1-spec.md.
      if (
        params.internalPrediction !== null &&
        params.alternativePicked !== null &&
        params.alternativePicked === params.internalPrediction
      ) {
        return "agreement";
      }
      return "correction";
  }
}

export async function emitTrainingRow(params: EmitParams): Promise<void> {
  const userTier = await resolveUserTier(params.userId);

  const fatigue = detectFatigueAccept({
    action: params.action,
    dwellMs: params.dwellMs,
    failureModeSeverity: params.failureModeSeverity,
    surfaceOrigin: params.surfaceOrigin,
    queuePosition: params.queuePosition,
  });

  const engagementType: EngagementType = fatigue ? "fatigue_accept" : "engaged";

  // Training-weight policy (expert tier + non-fatigue = 1.0, else 0).
  // Source: brainstorm D3 tier-split; q1-spec.md confirms expert-only weighting.
  // When the "verified-editorial" tier is earned by standard users, update here.
  const isExpert = userTier === "expert" || userTier === "expert-calibrator";
  const trainingWeight = fatigue ? 0 : isExpert ? 1.0 : 0;

  if (params.internalPrediction === null) {
    // Day-zero invariant warning: attempt generation did not persist the
    // prediction text. Row is still written so the action is auditable, but
