```typescript
import { emitTrainingRow } from "@/lib/training-rows/emit";
import { randomUUID } from "node:crypto";

const scoutSessionId = randomUUID();

for (let i = 0; i < validated.length; i++) {
  const decision = validated[i];
  // Resolve proposed hunk text + severity — exact API TBD per Scout hunk model;
  // verify with packages/pipeline-worker/src/training-scout.ts, which generates hunks.
  const proposedText = await getProposedHunkText(pair, decision.hunkId);
  const action: TrainingAction =
    decision.decision === "accepted"
      ? "accept"
      : decision.reEditText?.trim()
      ? "free_text"
      : "reject";
  const alternativePicked =
    action === "accept" ? proposedText
    : action === "free_text" ? decision.reEditText!.trim()
    : null;

  try {
    await emitTrainingRow({
      userId,
      sessionId: scoutSessionId,
      pieceId: pair.id,
      paragraphIdx: i,  // decision index proxy
      attemptId: `${pair.id}:${decision.hunkId}`,
      action,
      alternativesShown: [proposedText],
      alternativePicked,
      dwellMs: 0,             // Scout does not record per-hunk dwell today (TODO follow-up)
      queuePosition: i,       // position within the Scout batch
      surfaceOrigin: "scout-web",
      attemptModelConfidence: pair.texturaizeScore ?? 0,
      rulesShown: decision.pillarTags ?? [],
      displayMode: "first-reader",
      internalPrediction: proposedText,
      failureModeSeverity: pair.texturaizeScore ?? 0,
    });
  } catch (emitErr) {
    console.error("training_rows emit failed (scout)", {
      pairId: pair.id, hunkId: decision.hunkId, error: String(emitErr),
    });
  }
}
```

